module top_module(
    input [3:0] in,
    input [1:0] unsel,
    output reg out,
    input VDD, VSS, VDDIO
);always @ (unsel or in) begin
    case (unsel)
        2'b00: out = in[0];
        2'b01: out = in[1];
        2'b10: out = in[2];
        2'b11: out = in[3];
    endcase
end

endmodule
